"use client";

import { use, Suspense } from "react";
import dynamic from "next/dynamic";
import Link from "next/link";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { useBatchInfo, useBatchState, useBatchURI } from "@/hooks/use-contract";
import { IpfsMetadata } from "@/components/ipfs-metadata";
import { BatchEventHistory } from "@/components/batch-event-history";
import { getContractAddress, DEFAULT_CHAIN_ID } from "@/config/contract";
import {
  BatchState,
  BATCH_STATE_LABELS,
  BATCH_STATE_ICONS,
  BATCH_STATE_COLORS,
  PRODUCT_TYPE_LABELS,
  ProductType,
} from "@/config/contract";

// Dynamic import for Leaflet (no SSR ÔÇö uses `window`)
const OriginMap = dynamic(
  () => import("@/components/origin-map").then((m) => m.OriginMap),
  {
    ssr: false,
    loading: () => (
      <div className="h-[300px] bg-muted animate-pulse rounded-lg" />
    ),
  }
);

export default function TrackBatchPage({
  params,
}: {
  params: Promise<{ batchId: string }>;
}) {
  const { batchId } = use(params);

  const {
    data: batchInfo,
    isLoading: infoLoading,
    error: infoError,
  } = useBatchInfo(BigInt(batchId));

  const { data: batchState, isLoading: stateLoading } = useBatchState(
    BigInt(batchId)
  );

  const { data: uri } = useBatchURI(BigInt(batchId));

  if (infoLoading || stateLoading) {
    return (
      <div className="container mx-auto px-4 py-12">
        <div className="max-w-3xl mx-auto text-center">
          <div className="animate-pulse">
            <div className="h-8 bg-muted rounded w-1/3 mx-auto mb-4" />
            <div className="h-4 bg-muted rounded w-2/3 mx-auto mb-8" />
            <div className="grid gap-4">
              {[1, 2, 3].map((i) => (
                <div key={i} className="h-24 bg-muted rounded" />
              ))}
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (infoError) {
    return (
      <div className="container mx-auto px-4 py-12">
        <div className="max-w-3xl mx-auto text-center">
          <h1 className="text-2xl font-bold mb-4">ÔØî Lote No Encontrado</h1>
          <p className="text-muted-foreground mb-4">
            El Batch ID <code className="font-mono text-sm">{batchId}</code> no
            existe en la blockchain.
          </p>
          <p className="text-sm text-muted-foreground">
            Verifica que el ID sea correcto o escanea el QR del producto.
          </p>
        </div>
      </div>
    );
  }

  // Destructure batch info (wagmi v3 returns a named struct)
  const info = batchInfo as
    | {
        farmer: `0x${string}`;
        productType: number;
        variety: string;
        weightKg: bigint;
        originHash: `0x${string}`;
        region: string;
        harvestDate: bigint;
        lastUpdate: bigint;
        currentState: number;
        ipfsHash: string;
      }
    | undefined;

  const farmer = info?.farmer ?? "0x";
  const productType = info?.productType ?? 0;
  const variety = info?.variety ?? "";
  const weightKg = info?.weightKg ?? 0n;
  const region = info?.region ?? "";
  const harvestDate = info?.harvestDate ?? 0n;
  const ipfsHash = info?.ipfsHash ?? "";
  const currentState = info?.currentState ?? 0;

  const stateNum = (batchState as number) ?? currentState;
  const stateEnum = stateNum as BatchState;

  return (
    <div className="container mx-auto px-4 py-12">
      <div className="max-w-3xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <div className="flex items-center gap-3 mb-2">
            <Badge
              variant="outline"
              className="text-xs font-mono"
            >
              Batch #{batchId.slice(0, 12)}...
            </Badge>
            <Badge className={`${BATCH_STATE_COLORS[stateEnum]} text-white`}>
              {BATCH_STATE_ICONS[stateEnum]} {BATCH_STATE_LABELS[stateEnum]}
            </Badge>
          </div>
          <h1 className="text-3xl font-bold">{variety}</h1>
          <p className="text-muted-foreground">
            {PRODUCT_TYPE_LABELS[productType as ProductType]} ÔÇó {region}
          </p>
        </div>

        {/* Timeline */}
        <Card className="mb-6">
          <CardHeader>
            <CardTitle className="text-lg">
              ­ƒôì Timeline de Trazabilidad
            </CardTitle>
            <CardDescription>
              Cada estado est├í verificado on-chain en Polygon
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {Object.values(BatchState)
                .filter((v) => typeof v === "number")
                .map((state) => {
                  const s = state as BatchState;
                  const isCompleted = s <= stateEnum;
                  const isCurrent = s === stateEnum;

                  return (
                    <div key={s} className="flex items-center gap-4">
                      <div
                        className={`flex-shrink-0 w-10 h-10 rounded-full flex items-center justify-center text-lg ${
                          isCompleted
                            ? `${BATCH_STATE_COLORS[s]} text-white`
                            : "bg-muted text-muted-foreground"
                        } ${isCurrent ? "ring-2 ring-offset-2 ring-primary" : ""}`}
                      >
                        {BATCH_STATE_ICONS[s]}
                      </div>
                      <div className="flex-1">
                        <p
                          className={`text-sm font-medium ${
                            isCompleted
                              ? "text-foreground"
                              : "text-muted-foreground"
                          }`}
                        >
                          {BATCH_STATE_LABELS[s]}
                        </p>
                        {isCurrent && (
                          <p className="text-xs text-primary font-medium">
                            ÔåÉ Estado actual
                          </p>
                        )}
                      </div>
                      {isCompleted && (
                        <span className="text-green-500 text-sm">Ô£ô</span>
                      )}
                    </div>
                  );
                })}
            </div>
          </CardContent>
        </Card>

        {/* Details */}
        <Card className="mb-6">
          <CardHeader>
            <CardTitle className="text-lg">­ƒôï Detalles del Lote</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <DetailRow label="Producto" value={PRODUCT_TYPE_LABELS[productType as ProductType]} />
            <DetailRow label="Variedad" value={variety} />
            <Separator />
            <DetailRow label="Regi├│n" value={region} />
            <DetailRow
              label="Peso"
              value={`${(Number(weightKg) / 100).toFixed(2)} kg`}
            />
            <DetailRow
              label="Fecha Cosecha"
              value={new Date(Number(harvestDate) * 1000).toLocaleDateString(
                "es-EC"
              )}
            />
            <Separator />
            <DetailRow
              label="Agricultor"
              value={`${farmer.slice(0, 8)}...${farmer.slice(-6)}`}
              mono
            />
            {uri && (
              <DetailRow
                label="IPFS"
                value={String(uri)}
                mono
                href={`https://ipfs.io/ipfs/${ipfsHash}`}
              />
            )}
          </CardContent>
        </Card>

        {/* Origin Map */}
        {region && (
          <Card className="mb-6">
            <CardHeader>
              <CardTitle className="text-lg">­ƒù║´©Å Origen en Ecuador</CardTitle>
              <CardDescription>
                Ubicaci├│n aproximada de la finca de origen
              </CardDescription>
            </CardHeader>
            <CardContent>
              <OriginMap region={region} height={350} />
            </CardContent>
          </Card>
        )}

        {/* IPFS Metadata */}
        {ipfsHash && (
          <div className="mb-6">
            <IpfsMetadata ipfsHash={ipfsHash} uri={uri ? String(uri) : undefined} />
          </div>
        )}

        {/* On-Chain Event History */}
        <div className="mb-6">
          <BatchEventHistory
            batchId={BigInt(batchId)}
            contractAddress={getContractAddress(DEFAULT_CHAIN_ID)}
          />
        </div>

        {/* Back link */}
        <div className="text-center mt-8">
          <Button asChild variant="outline">
            <Link href="/track">ÔåÉ Buscar otro lote</Link>
          </Button>
        </div>
      </div>
    </div>
  );
}

function DetailRow({
  label,
  value,
  mono,
  href,
}: {
  label: string;
  value: string;
  mono?: boolean;
  href?: string;
}) {
  return (
    <div className="flex justify-between items-center">
      <span className="text-sm text-muted-foreground">{label}</span>
      {href ? (
        <a
          href={href}
          target="_blank"
          rel="noopener noreferrer"
          className={`text-sm text-primary hover:underline ${
            mono ? "font-mono" : ""
          }`}
        >
          {value}
        </a>
      ) : (
        <span className={`text-sm ${mono ? "font-mono" : ""}`}>{value}</span>
      )}
    </div>
  );
}

"use client";

import { useState, useCallback } from "react";
import { useRouter } from "next/navigation";
import { QrScanner } from "@/components/qr-scanner";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";

export default function VerifyPage() {
  const router = useRouter();
  const [scanResult, setScanResult] = useState<string | null>(null);
  const [scanError, setScanError] = useState<string | null>(null);

  const handleScanSuccess = useCallback(
    (decodedText: string) => {
      setScanResult(decodedText);
      setScanError(null);

      // If the QR contains a URL with /track/BATCHID, navigate directly
      const trackMatch = decodedText.match(/\/track\/(\d+)/);
      if (trackMatch) {
        router.push(`/track/${trackMatch[1]}`);
        return;
      }

      // If it's a pure numeric batchId
      if (/^\d+$/.test(decodedText.trim())) {
        router.push(`/track/${decodedText.trim()}`);
        return;
      }

      // Otherwise show result with option to search
      setScanError(
        "El QR no contiene un Batch ID v├ílido. Intenta con otro c├│digo."
      );
    },
    [router]
  );

  return (
    <div className="container mx-auto px-4 py-12">
      <div className="max-w-2xl mx-auto">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold mb-2">­ƒô▒ Verificar Producto</h1>
          <p className="text-muted-foreground">
            Escanea el c├│digo QR en el empaque del producto para ver su journey
            completo desde el campo ecuatoriano hasta tu mesa.
          </p>
        </div>

        {/* Scanner Card */}
        <Card className="mb-6">
          <CardHeader>
            <CardTitle className="text-lg">Esc├íner QR</CardTitle>
            <CardDescription>
              Apunta la c├ímara al c├│digo QR del empaque. Se reconocer├í
              autom├íticamente.
            </CardDescription>
          </CardHeader>
          <CardContent className="flex justify-center">
            <QrScanner
              onScanSuccess={handleScanSuccess}
              width={320}
              height={320}
            />
          </CardContent>
        </Card>

        {/* Result feedback */}
        {scanResult && !scanError && (
          <Card className="mb-6 border-green-500/50">
            <CardContent className="pt-6">
              <div className="flex items-center gap-3">
                <span className="text-2xl">Ô£à</span>
                <div>
                  <p className="font-medium">QR Detectado</p>
                  <p className="text-sm text-muted-foreground font-mono">
                    {scanResult.length > 60
                      ? `${scanResult.slice(0, 60)}...`
                      : scanResult}
                  </p>
                  <p className="text-xs text-primary mt-1">
                    Redirigiendo al tracking...
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        )}

        {scanError && (
          <Card className="mb-6 border-destructive/50">
            <CardContent className="pt-6">
              <div className="flex items-center gap-3">
                <span className="text-2xl">ÔÜá´©Å</span>
                <div>
                  <p className="font-medium text-destructive">
                    QR no reconocido
                  </p>
                  <p className="text-sm text-muted-foreground">{scanError}</p>
                  {scanResult && (
                    <p className="text-xs text-muted-foreground font-mono mt-1">
                      Contenido: {scanResult}
                    </p>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>
        )}

        {/* Instructions */}
        <Card>
          <CardHeader>
            <CardTitle className="text-lg">┬┐C├│mo funciona?</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {INSTRUCTIONS.map((inst, i) => (
                <div key={i} className="flex items-start gap-3">
                  <Badge
                    variant="outline"
                    className="flex-shrink-0 h-6 w-6 rounded-full flex items-center justify-center text-xs p-0"
                  >
                    {i + 1}
                  </Badge>
                  <div>
                    <p className="text-sm font-medium">{inst.title}</p>
                    <p className="text-xs text-muted-foreground">{inst.desc}</p>
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-6 pt-4 border-t">
              <p className="text-xs text-muted-foreground text-center">
                Tambi├®n puedes ingresar el Batch ID manualmente en{" "}
                <a href="/track" className="text-primary hover:underline">
                  Rastrear Lote
                </a>
                .
              </p>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

const INSTRUCTIONS = [
  {
    title: "Busca el c├│digo QR",
    desc: "Est├í impreso en la etiqueta del empaque del producto de cacao o caf├®.",
  },
  {
    title: "Escanea con la c├ímara",
    desc: "Permite el acceso a la c├ímara y apunta al c├│digo QR. Se detectar├í autom├íticamente.",
  },
  {
    title: "Ve el journey completo",
    desc: "Ser├ís redirigido a la p├ígina de trazabilidad donde ver├ís cada estado del lote verificado en blockchain.",
  },
];

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { TxStatus } from "@/components/tx-status";
import { useAdvanceState } from "@/hooks/use-contract-write";
import { useBatchInfo, useBatchState } from "@/hooks/use-contract";
import {
  BatchState,
  BATCH_STATE_LABELS,
  BATCH_STATE_ICONS,
  BATCH_STATE_COLORS,
  STATE_REQUIRED_ROLE,
} from "@/config/contract";

export function AdvanceStateForm() {
  const { advanceState, hash, isPending, isConfirming, isSuccess, error, reset } =
    useAdvanceState();

  const [batchId, setBatchId] = useState("");
  const [notes, setNotes] = useState("");

  const batchIdBigInt = batchId.trim() ? BigInt(batchId.trim()) : 0n;

  const { data: batchInfo, isLoading: infoLoading } = useBatchInfo(batchIdBigInt);
  const { data: batchState, isLoading: stateLoading } = useBatchState(batchIdBigInt);

  const info = batchInfo as
    | {
        farmer: `0x${string}`;
        productType: number;
        variety: string;
        weightKg: bigint;
        region: string;
        currentState: number;
      }
    | undefined;

  const currentState = (batchState as number) ?? info?.currentState ?? -1;
  const nextState = currentState >= 0 && currentState < 5 ? currentState + 1 : -1;
  const isTerminal = currentState === BatchState.Delivered;

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    reset();
    if (batchIdBigInt > 0n && nextState >= 0) {
      advanceState(batchIdBigInt, nextState, notes);
    }
  }

  const hasBatch = batchIdBigInt > 0n && info && !infoLoading;

  return (
    <Card>
      <CardHeader>
        <CardTitle>ÔÅ¡´©Å Avanzar Estado de Lote</CardTitle>
        <CardDescription>
          Avanza al siguiente estado en la cadena de trazabilidad. Cada
          transici├│n requiere un rol espec├¡fico.
        </CardDescription>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Batch ID */}
          <div className="space-y-2">
            <Label htmlFor="advBatchId">Batch ID *</Label>
            <Input
              id="advBatchId"
              type="text"
              placeholder="Ingresa el Batch ID num├®rico"
              value={batchId}
              onChange={(e) => {
                setBatchId(e.target.value.replace(/[^0-9]/g, ""));
                reset();
              }}
              className="font-mono"
            />
          </div>

          {/* Batch Preview */}
          {infoLoading || stateLoading ? (
            <div className="animate-pulse h-20 bg-muted rounded-lg" />
          ) : hasBatch ? (
            <div className="rounded-lg border p-4 space-y-3">
              <div className="flex items-center justify-between">
                <div>
                  <p className="font-medium">{info.variety}</p>
                  <p className="text-sm text-muted-foreground">{info.region}</p>
                </div>
                <Badge className={`${BATCH_STATE_COLORS[currentState as BatchState]} text-white`}>
                  {BATCH_STATE_ICONS[currentState as BatchState]}{" "}
                  {BATCH_STATE_LABELS[currentState as BatchState]}
                </Badge>
              </div>

              {!isTerminal && nextState >= 0 ? (
                <div className="flex items-center gap-2 text-sm">
                  <span className="text-muted-foreground">Siguiente:</span>
                  <Badge variant="outline">
                    {BATCH_STATE_ICONS[nextState as BatchState]}{" "}
                    {BATCH_STATE_LABELS[nextState as BatchState]}
                  </Badge>
                  <span className="text-xs text-muted-foreground">
                    (requiere {STATE_REQUIRED_ROLE[currentState as BatchState]})
                  </span>
                </div>
              ) : (
                <p className="text-sm text-emerald-600 font-medium">
                  Ô£à Este lote ya est├í entregado (estado terminal).
                </p>
              )}
            </div>
          ) : batchIdBigInt > 0n ? (
            <div className="rounded-lg border border-destructive/50 p-4 text-center">
              <p className="text-sm text-destructive">
                No se encontr├│ un lote con ese ID.
              </p>
            </div>
          ) : null}

          {/* Notes */}
          <div className="space-y-2">
            <Label htmlFor="advNotes">
              Notas{" "}
              <span className="text-muted-foreground">(quedan registradas on-chain)</span>
            </Label>
            <Textarea
              id="advNotes"
              placeholder="Ej: Fermentaci├│n completada, 5 d├¡as en caj├│n de madera"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              rows={2}
            />
          </div>

          {/* Submit */}
          <Button
            type="submit"
            disabled={!hasBatch || isTerminal || isPending || isConfirming}
            className="w-full"
          >
            {isPending
              ? "Esperando wallet..."
              : isConfirming
                ? "Confirmando..."
                : isTerminal
                  ? "Estado terminal ÔÇö no se puede avanzar"
                  : `ÔÅ¡´©Å Avanzar a ${nextState >= 0 ? BATCH_STATE_LABELS[nextState as BatchState] : "..."}`}
          </Button>

          {/* Status */}
          <TxStatus
            isPending={isPending}
            isConfirming={isConfirming}
            isSuccess={isSuccess}
            error={error}
            hash={hash}
            successMessage={`Estado avanzado a ${nextState >= 0 ? BATCH_STATE_LABELS[nextState as BatchState] : "nuevo estado"}`}
          />
        </form>
      </CardContent>
    </Card>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import { usePublicClient } from "wagmi";
import { parseAbiItem } from "viem";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  BatchState,
  BATCH_STATE_LABELS,
  BATCH_STATE_ICONS,
  BATCH_STATE_COLORS,
  PRODUCT_TYPE_LABELS,
  ProductType,
  getContractAddress,
  DEFAULT_CHAIN_ID,
} from "@/config/contract";
import { useBatchInfo, useBatchState } from "@/hooks/use-contract";

interface BatchSummary {
  batchId: bigint;
  farmer: string;
  productType: number;
  weightKg: bigint;
  timestamp: bigint;
}

const BATCH_CREATED_EVENT = parseAbiItem(
  "event BatchCreated(uint256 indexed batchId, address indexed farmer, uint8 productType, uint256 weightKg, uint256 timestamp)"
);

export function BatchDashboard() {
  const publicClient = usePublicClient();
  const [batches, setBatches] = useState<BatchSummary[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [filter, setFilter] = useState<string>("all");
  const [search, setSearch] = useState("");

  const fetchBatches = useCallback(async () => {
    if (!publicClient) return;
    setLoading(true);
    setError(null);

    try {
      const contractAddress = getContractAddress(DEFAULT_CHAIN_ID);
      const logs = await publicClient.getLogs({
        address: contractAddress,
        event: BATCH_CREATED_EVENT,
        fromBlock: 0n,
        toBlock: "latest",
      });

      const items: BatchSummary[] = logs.map((log) => {
        const args = (log as unknown as { args: Record<string, unknown> }).args;
        return {
          batchId: args.batchId as bigint,
          farmer: String(args.farmer ?? ""),
          productType: Number(args.productType ?? 0),
          weightKg: args.weightKg as bigint,
          timestamp: args.timestamp as bigint,
        };
      });

      // Reverse so newest first
      setBatches(items.reverse());
    } catch (err) {
      setError(
        err instanceof Error ? err.message : "Error al cargar lotes"
      );
    } finally {
      setLoading(false);
    }
  }, [publicClient]);

  useEffect(() => {
    fetchBatches();
  }, [fetchBatches]);

  // Filter by product type
  const filtered = batches.filter((b) => {
    if (filter !== "all" && b.productType !== parseInt(filter)) return false;
    if (search.trim()) {
      const s = search.toLowerCase();
      const idStr = b.batchId.toString();
      return (
        idStr.includes(s) ||
        b.farmer.toLowerCase().includes(s)
      );
    }
    return true;
  });

  return (
    <Card>
      <CardHeader>
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div>
            <CardTitle>­ƒôè Dashboard de Lotes</CardTitle>
            <CardDescription>
              {batches.length} lote{batches.length !== 1 ? "s" : ""} registrado
              {batches.length !== 1 ? "s" : ""} en la blockchain
            </CardDescription>
          </div>
          <Button variant="outline" size="sm" onClick={fetchBatches} disabled={loading}>
            ­ƒöä Actualizar
          </Button>
        </div>
      </CardHeader>
      <CardContent>
        {/* Filters */}
        <div className="flex flex-col sm:flex-row gap-3 mb-4">
          <Input
            placeholder="Buscar por Batch ID o farmer..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="sm:max-w-xs"
          />
          <Select value={filter} onValueChange={setFilter}>
            <SelectTrigger className="sm:max-w-[180px]">
              <SelectValue placeholder="Todos" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos los productos</SelectItem>
              <SelectItem value="0">­ƒ½ÿ Cacao</SelectItem>
              <SelectItem value="1">Ôÿò Caf├®</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Loading */}
        {loading && (
          <div className="space-y-2">
            {[1, 2, 3].map((i) => (
              <div key={i} className="h-12 bg-muted rounded animate-pulse" />
            ))}
          </div>
        )}

        {/* Error */}
        {error && (
          <div className="text-center py-8">
            <p className="text-sm text-destructive mb-2">{error}</p>
            <p className="text-xs text-muted-foreground">
              Verifica que el nodo RPC y la direcci├│n del contrato sean correctos.
            </p>
          </div>
        )}

        {/* Empty */}
        {!loading && !error && filtered.length === 0 && (
          <div className="text-center py-8">
            <span className="text-4xl block mb-2">­ƒô¡</span>
            <p className="text-sm text-muted-foreground">
              {batches.length === 0
                ? "No hay lotes registrados a├║n."
                : "No se encontraron lotes con estos filtros."}
            </p>
          </div>
        )}

        {/* Table */}
        {!loading && !error && filtered.length > 0 && (
          <div className="rounded-md border overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Batch ID</TableHead>
                  <TableHead>Producto</TableHead>
                  <TableHead>Peso</TableHead>
                  <TableHead>Farmer</TableHead>
                  <TableHead>Fecha</TableHead>
                  <TableHead className="text-center">Estado</TableHead>
                  <TableHead></TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filtered.map((batch) => (
                  <BatchRow key={batch.batchId.toString()} batch={batch} />
                ))}
              </TableBody>
            </Table>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

function BatchRow({ batch }: { batch: BatchSummary }) {
  const { data: stateData } = useBatchState(batch.batchId);
  const state = (stateData as number) ?? 0;

  const idStr = batch.batchId.toString();
  const shortId = idStr.length > 12 ? `${idStr.slice(0, 6)}...${idStr.slice(-6)}` : idStr;

  return (
    <TableRow>
      <TableCell className="font-mono text-xs">{shortId}</TableCell>
      <TableCell>
        {batch.productType === 0 ? "­ƒ½ÿ" : "Ôÿò"}{" "}
        {PRODUCT_TYPE_LABELS[batch.productType as ProductType]}
      </TableCell>
      <TableCell>{(Number(batch.weightKg) / 100).toFixed(2)} kg</TableCell>
      <TableCell className="font-mono text-xs">
        {batch.farmer.slice(0, 6)}...{batch.farmer.slice(-4)}
      </TableCell>
      <TableCell className="text-xs">
        {Number(batch.timestamp) > 0
          ? new Date(Number(batch.timestamp) * 1000).toLocaleDateString("es-EC")
          : "ÔÇö"}
      </TableCell>
      <TableCell className="text-center">
        <Badge className={`${BATCH_STATE_COLORS[state as BatchState]} text-white text-xs`}>
          {BATCH_STATE_ICONS[state as BatchState]}{" "}
          {BATCH_STATE_LABELS[state as BatchState]}
        </Badge>
      </TableCell>
      <TableCell>
        <Button asChild variant="ghost" size="sm">
          <Link href={`/track/${idStr}`}>Ver ÔåÆ</Link>
        </Button>
      </TableCell>
    </TableRow>
  );
}

"use client";

import { useAccount } from "wagmi";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { DEFAULT_ADMIN_ROLE } from "@/config/contract";
import { useHasRole, usePaused } from "@/hooks/use-contract";
import { usePause, useUnpause } from "@/hooks/use-contract-write";
import { TxStatus } from "@/components/tx-status";

export function ContractControl() {
  const { address } = useAccount();
  const { data: isAdmin } = useHasRole(
    DEFAULT_ADMIN_ROLE,
    address ?? "0x0000000000000000000000000000000000000000"
  );
  const { data: isPaused, isLoading: pauseLoading } = usePaused();
  const pause = usePause();
  const unpause = useUnpause();

  if (!isAdmin) {
    return (
      <Alert>
        <AlertDescription>
          Ôøö Solo cuentas con <strong>DEFAULT_ADMIN_ROLE</strong> pueden controlar el contrato.
        </AlertDescription>
      </Alert>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>ÔÜÖ´©Å Control del Contrato</CardTitle>
        <CardDescription>
          Pausa o reanuda el contrato. Cuando est├í pausado, no se pueden crear
          lotes ni avanzar estados.
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="flex items-center gap-4">
          <span className="text-sm font-medium">Estado actual:</span>
          {pauseLoading ? (
            <Badge variant="outline">Cargando...</Badge>
          ) : isPaused ? (
            <Badge variant="destructive">ÔÅ©´©Å Pausado</Badge>
          ) : (
            <Badge className="bg-green-700 text-white">ÔûÂ´©Å Activo</Badge>
          )}
        </div>

        <div className="flex gap-3">
          <Button
            variant="destructive"
            onClick={() => pause.pause()}
            disabled={!!isPaused || pause.isPending || pause.isConfirming}
          >
            {pause.isPending ? "Esperando..." : "ÔÅ©´©Å Pausar Contrato"}
          </Button>
          <Button
            className="bg-green-800 hover:bg-green-700 text-white"
            onClick={() => unpause.unpause()}
            disabled={!isPaused || unpause.isPending || unpause.isConfirming}
          >
            {unpause.isPending ? "Esperando..." : "ÔûÂ´©Å Reanudar Contrato"}
          </Button>
        </div>

        <TxStatus
          isPending={pause.isPending || unpause.isPending}
          isConfirming={pause.isConfirming || unpause.isConfirming}
          isSuccess={pause.isSuccess || unpause.isSuccess}
          error={pause.error || unpause.error}
          hash={pause.hash || unpause.hash}
          successMessage="Estado del contrato actualizado"
        />
      </CardContent>
    </Card>
  );
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { TxStatus } from "@/components/tx-status";
import { useCreateBatch, generateOriginHash } from "@/hooks/use-contract-write";
import { ProductType, PRODUCT_TYPE_LABELS } from "@/config/contract";

const REGIONS = [
  "Esmeraldas, Ecuador",
  "Los R├¡os, Ecuador",
  "Manab├¡, Ecuador",
  "Guayas, Ecuador",
  "El Oro, Ecuador",
  "Santo Domingo, Ecuador",
  "Loja, Ecuador",
  "Zamora Chinchipe, Ecuador",
  "Bol├¡var, Ecuador",
  "Cotopaxi, Ecuador",
  "Napo, Ecuador",
  "Sucumb├¡os, Ecuador",
  "Orellana, Ecuador",
  "Morona Santiago, Ecuador",
  "Pastaza, Ecuador",
  "Gal├ípagos, Ecuador",
];

export function CreateBatchForm() {
  const { createBatch, hash, isPending, isConfirming, isSuccess, error, reset } =
    useCreateBatch();

  const [form, setForm] = useState({
    productType: "0",
    variety: "",
    weightKg: "",
    region: "",
    originDetail: "",
    harvestDate: "",
    ipfsHash: "",
  });

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    reset();

    const weightCentesimal = BigInt(Math.round(parseFloat(form.weightKg) * 100));
    const harvestTimestamp = BigInt(
      Math.floor(new Date(form.harvestDate).getTime() / 1000)
    );
    const originString = form.originDetail || form.region;
    const originHash = generateOriginHash(originString);

    createBatch({
      productType: parseInt(form.productType),
      variety: form.variety,
      weightKg: weightCentesimal,
      originHash,
      region: form.region,
      harvestDate: harvestTimestamp,
      ipfsHash: form.ipfsHash,
    });
  }

  function updateField(field: string, value: string) {
    setForm((prev) => ({ ...prev, [field]: value }));
  }

  const isValid =
    form.variety.trim() !== "" &&
    form.weightKg !== "" &&
    parseFloat(form.weightKg) > 0 &&
    form.region !== "" &&
    form.harvestDate !== "";

  return (
    <Card>
      <CardHeader>
        <CardTitle>­ƒôØ Crear Nuevo Lote</CardTitle>
        <CardDescription>
          Registra un nuevo lote de cacao o caf├® en la blockchain. Requiere rol
          FARMER_ROLE.
        </CardDescription>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Row 1: Product Type + Variety */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="productType">Tipo de Producto</Label>
              <Select
                value={form.productType}
                onValueChange={(v) => updateField("productType", v)}
              >
                <SelectTrigger id="productType">
                  <SelectValue placeholder="Seleccionar..." />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="0">
                    ­ƒ½ÿ {PRODUCT_TYPE_LABELS[ProductType.Cacao]}
                  </SelectItem>
                  <SelectItem value="1">
                    Ôÿò {PRODUCT_TYPE_LABELS[ProductType.Coffee]}
                  </SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="variety">Variedad *</Label>
              <Input
                id="variety"
                placeholder="Ej: Nacional Fino de Aroma"
                value={form.variety}
                onChange={(e) => updateField("variety", e.target.value)}
                required
              />
            </div>
          </div>

          {/* Row 2: Weight + Harvest Date */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="weightKg">Peso (kg) *</Label>
              <Input
                id="weightKg"
                type="number"
                step="0.01"
                min="0.01"
                placeholder="Ej: 150.50"
                value={form.weightKg}
                onChange={(e) => updateField("weightKg", e.target.value)}
                required
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="harvestDate">Fecha de Cosecha *</Label>
              <Input
                id="harvestDate"
                type="date"
                value={form.harvestDate}
                onChange={(e) => updateField("harvestDate", e.target.value)}
                required
              />
            </div>
          </div>

          {/* Region */}
          <div className="space-y-2">
            <Label htmlFor="region">Regi├│n de Origen *</Label>
            <Select
              value={form.region}
              onValueChange={(v) => updateField("region", v)}
            >
              <SelectTrigger id="region">
                <SelectValue placeholder="Seleccionar regi├│n..." />
              </SelectTrigger>
              <SelectContent>
                {REGIONS.map((r) => (
                  <SelectItem key={r} value={r}>
                    {r}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Origin Detail (para el hash) */}
          <div className="space-y-2">
            <Label htmlFor="originDetail">
              Detalle de Origen{" "}
              <span className="text-muted-foreground">(opcional, para hash)</span>
            </Label>
            <Textarea
              id="originDetail"
              placeholder="Ej: Finca La Aurora, km 45 v├¡a Quinind├®, Esmeraldas"
              value={form.originDetail}
              onChange={(e) => updateField("originDetail", e.target.value)}
              rows={2}
            />
            <p className="text-xs text-muted-foreground">
              Se genera un hash keccak256 de este texto como identificador ├║nico de origen.
            </p>
          </div>

          {/* IPFS Hash */}
          <div className="space-y-2">
            <Label htmlFor="ipfsHash">
              IPFS Hash{" "}
              <span className="text-muted-foreground">(opcional)</span>
            </Label>
            <Input
              id="ipfsHash"
              placeholder="Ej: QmXoypiz..."
              value={form.ipfsHash}
              onChange={(e) => updateField("ipfsHash", e.target.value)}
              className="font-mono text-sm"
            />
          </div>

          {/* Submit */}
          <Button
            type="submit"
            disabled={!isValid || isPending || isConfirming}
            className="w-full"
          >
            {isPending
              ? "Esperando wallet..."
              : isConfirming
                ? "Confirmando..."
                : "­ƒî▒ Crear Lote en Blockchain"}
          </Button>

          {/* Status */}
          <TxStatus
            isPending={isPending}
            isConfirming={isConfirming}
            isSuccess={isSuccess}
            error={error}
            hash={hash}
            successMessage="┬íLote creado exitosamente en la blockchain!"
          />
        </form>
      </CardContent>
    </Card>
  );
}

"use client";

import { useState } from "react";
import { isAddress } from "viem";
import { useAccount } from "wagmi";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Alert, AlertDescription } from "@/components/ui/alert";
import {
  ROLES,
  DEFAULT_ADMIN_ROLE,
  FARMER_ROLE,
  PROCESSOR_ROLE,
  EXPORTER_ROLE,
  BUYER_ROLE,
} from "@/config/contract";
import { useHasRole } from "@/hooks/use-contract";
import { useGrantRole, useRevokeRole } from "@/hooks/use-contract-write";
import { TxStatus } from "@/components/tx-status";

const ROLE_MAP: Record<string, `0x${string}`> = {
  FARMER_ROLE: FARMER_ROLE,
  PROCESSOR_ROLE: PROCESSOR_ROLE,
  EXPORTER_ROLE: EXPORTER_ROLE,
  BUYER_ROLE: BUYER_ROLE,
  DEFAULT_ADMIN_ROLE: DEFAULT_ADMIN_ROLE,
};

export function RoleManagement() {
  const { address } = useAccount();

  // Admin check
  const { data: isAdmin } = useHasRole(
    DEFAULT_ADMIN_ROLE,
    address ?? "0x0000000000000000000000000000000000000000"
  );

  // Grant form
  const [grantAddress, setGrantAddress] = useState("");
  const [grantRole, setGrantRole] = useState("");
  const grant = useGrantRole();

  // Revoke form
  const [revokeAddress, setRevokeAddress] = useState("");
  const [revokeRole, setRevokeRole] = useState("");
  const revoke = useRevokeRole();

  // Lookup
  const [lookupAddress, setLookupAddress] = useState("");
  const [lookupActive, setLookupActive] = useState(false);

  const handleGrant = () => {
    if (!grantAddress || !grantRole) return;
    if (!isAddress(grantAddress)) return;
    const roleHash = ROLE_MAP[grantRole];
    if (!roleHash) return;
    grant.grantRole(roleHash, grantAddress as `0x${string}`);
  };

  const handleRevoke = () => {
    if (!revokeAddress || !revokeRole) return;
    if (!isAddress(revokeAddress)) return;
    const roleHash = ROLE_MAP[revokeRole];
    if (!roleHash) return;
    revoke.revokeRole(roleHash, revokeAddress as `0x${string}`);
  };

  if (!isAdmin) {
    return (
      <Alert>
        <AlertDescription>
          Ôøö Solo cuentas con <strong>DEFAULT_ADMIN_ROLE</strong> pueden gestionar roles.
          {address && (
            <span className="block text-xs font-mono mt-1 text-muted-foreground">
              Tu wallet: {address}
            </span>
          )}
        </AlertDescription>
      </Alert>
    );
  }

  return (
    <div className="space-y-6">
      {/* Grant Role */}
      <Card>
        <CardHeader>
          <CardTitle>Ô£à Otorgar Rol</CardTitle>
          <CardDescription>
            Asigna un rol a una direcci├│n de wallet
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="grant-addr">Direcci├│n de Wallet</Label>
              <Input
                id="grant-addr"
                placeholder="0x..."
                value={grantAddress}
                onChange={(e) => setGrantAddress(e.target.value)}
              />
              {grantAddress && !isAddress(grantAddress) && (
                <p className="text-xs text-destructive">Direcci├│n inv├ílida</p>
              )}
            </div>
            <div className="space-y-2">
              <Label htmlFor="grant-role">Rol</Label>
              <Select value={grantRole} onValueChange={setGrantRole}>
                <SelectTrigger id="grant-role">
                  <SelectValue placeholder="Seleccionar rol" />
                </SelectTrigger>
                <SelectContent>
                  {ROLES.map((r) => (
                    <SelectItem key={r.key} value={r.key}>
                      {r.icon} {r.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>
          <Button
            onClick={handleGrant}
            disabled={
              !grantAddress ||
              !grantRole ||
              !isAddress(grantAddress) ||
              grant.isPending
            }
            className="bg-green-800 hover:bg-green-700 text-white"
          >
            {grant.isPending ? "Enviando..." : "Otorgar Rol"}
          </Button>
          <TxStatus
            hash={grant.hash}
            isPending={grant.isPending}
            isConfirming={grant.isConfirming}
            isSuccess={grant.isSuccess}
            error={grant.error}
          />
        </CardContent>
      </Card>

      {/* Revoke Role */}
      <Card>
        <CardHeader>
          <CardTitle>­ƒÜ½ Revocar Rol</CardTitle>
          <CardDescription>
            Elimina un rol de una direcci├│n de wallet
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="revoke-addr">Direcci├│n de Wallet</Label>
              <Input
                id="revoke-addr"
                placeholder="0x..."
                value={revokeAddress}
                onChange={(e) => setRevokeAddress(e.target.value)}
              />
              {revokeAddress && !isAddress(revokeAddress) && (
                <p className="text-xs text-destructive">Direcci├│n inv├ílida</p>
              )}
            </div>
            <div className="space-y-2">
              <Label htmlFor="revoke-role">Rol</Label>
              <Select value={revokeRole} onValueChange={setRevokeRole}>
                <SelectTrigger id="revoke-role">
                  <SelectValue placeholder="Seleccionar rol" />
                </SelectTrigger>
                <SelectContent>
                  {ROLES.map((r) => (
                    <SelectItem key={r.key} value={r.key}>
                      {r.icon} {r.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>
          <Button
            onClick={handleRevoke}
            disabled={
              !revokeAddress ||
              !revokeRole ||
              !isAddress(revokeAddress) ||
              revoke.isPending
            }
            variant="destructive"
          >
            {revoke.isPending ? "Enviando..." : "Revocar Rol"}
          </Button>
          <TxStatus
            hash={revoke.hash}
            isPending={revoke.isPending}
            isConfirming={revoke.isConfirming}
            isSuccess={revoke.isSuccess}
            error={revoke.error}
          />
        </CardContent>
      </Card>

      {/* Role Lookup */}
      <Card>
        <CardHeader>
          <CardTitle>­ƒöì Consultar Roles</CardTitle>
          <CardDescription>
            Verifica qu├® roles tiene una direcci├│n
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex gap-3">
            <Input
              placeholder="0x... direcci├│n a consultar"
              value={lookupAddress}
              onChange={(e) => {
                setLookupAddress(e.target.value);
                setLookupActive(false);
              }}
              className="flex-1"
            />
            <Button
              onClick={() => setLookupActive(true)}
              disabled={!isAddress(lookupAddress)}
              variant="outline"
            >
              Consultar
            </Button>
          </div>
          {lookupActive && isAddress(lookupAddress) && (
            <RoleLookupTable address={lookupAddress as `0x${string}`} />
          )}
        </CardContent>
      </Card>
    </div>
  );
}

function RoleLookupTable({ address }: { address: `0x${string}` }) {
  return (
    <div className="rounded-md border mt-2">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Rol</TableHead>
            <TableHead className="text-center">Estado</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {ROLES.map((role) => (
            <RoleLookupRow key={role.key} roleKey={role.key} address={address} />
          ))}
        </TableBody>
      </Table>
    </div>
  );
}

function RoleLookupRow({
  roleKey,
  address,
}: {
  roleKey: string;
  address: `0x${string}`;
}) {
  const roleHash = ROLE_MAP[roleKey];
  const { data: hasRole, isLoading } = useHasRole(roleHash, address);
  const role = ROLES.find((r) => r.key === roleKey);

  return (
    <TableRow>
      <TableCell>
        {role?.icon} {role?.label}
      </TableCell>
      <TableCell className="text-center">
        {isLoading ? (
          <Badge variant="outline">Cargando...</Badge>
        ) : hasRole ? (
          <Badge className="bg-green-700 text-white">Ô£à Activo</Badge>
        ) : (
          <Badge variant="secondary">ÔÇö Sin rol</Badge>
        )}
      </TableCell>
    </TableRow>
  );
}

"use client";

import { useEffect, useState } from "react";
import { usePublicClient } from "wagmi";
import { parseAbiItem, type Log } from "viem";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  BATCH_STATE_LABELS,
  BATCH_STATE_ICONS,
  BATCH_STATE_COLORS,
  BatchState,
} from "@/config/contract";

interface BatchEvent {
  type: "created" | "stateChanged" | "metadataUpdated";
  blockNumber: bigint;
  timestamp?: number;
  data: Record<string, unknown>;
  transactionHash: string;
}

interface BatchEventHistoryProps {
  /** The batch ID to fetch events for */
  batchId: bigint;
  /** Contract address */
  contractAddress: `0x${string}`;
}

const EVENT_ABIS = {
  created: parseAbiItem(
    "event BatchCreated(uint256 indexed batchId, address indexed farmer, uint8 productType, uint256 weightKg, uint256 timestamp)"
  ),
  stateChanged: parseAbiItem(
    "event BatchStateChanged(uint256 indexed batchId, uint8 indexed previousState, uint8 indexed newState, address actor, uint256 timestamp, string notes)"
  ),
  metadataUpdated: parseAbiItem(
    "event BatchMetadataUpdated(uint256 indexed batchId, string ipfsHash)"
  ),
};

/**
 * Displays on-chain event history for a specific batch.
 * Fetches BatchCreated, BatchStateChanged, and BatchMetadataUpdated logs.
 */
export function BatchEventHistory({
  batchId,
  contractAddress,
}: BatchEventHistoryProps) {
  const publicClient = usePublicClient();
  const [events, setEvents] = useState<BatchEvent[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;

    async function fetchEvents() {
      if (!publicClient) {
        setLoading(false);
        return;
      }

      setLoading(true);
      setError(null);

      try {
        // Fetch all three event types in parallel
        const [createdLogs, stateChangedLogs, metadataLogs] = await Promise.all(
          [
            publicClient.getLogs({
              address: contractAddress,
              event: EVENT_ABIS.created,
              args: { batchId },
              fromBlock: 0n,
              toBlock: "latest",
            }),
            publicClient.getLogs({
              address: contractAddress,
              event: EVENT_ABIS.stateChanged,
              args: { batchId },
              fromBlock: 0n,
              toBlock: "latest",
            }),
            publicClient.getLogs({
              address: contractAddress,
              event: EVENT_ABIS.metadataUpdated,
              args: { batchId },
              fromBlock: 0n,
              toBlock: "latest",
            }),
          ]
        );

        if (cancelled) return;

        const allEvents: BatchEvent[] = [];

        // Parse created events
        for (const log of createdLogs) {
          allEvents.push({
            type: "created",
            blockNumber: log.blockNumber,
            data: { ...(log as Log & { args: Record<string, unknown> }).args },
            transactionHash: log.transactionHash,
          });
        }

        // Parse state changed events
        for (const log of stateChangedLogs) {
          allEvents.push({
            type: "stateChanged",
            blockNumber: log.blockNumber,
            data: { ...(log as Log & { args: Record<string, unknown> }).args },
            transactionHash: log.transactionHash,
          });
        }

        // Parse metadata updated events
        for (const log of metadataLogs) {
          allEvents.push({
            type: "metadataUpdated",
            blockNumber: log.blockNumber,
            data: { ...(log as Log & { args: Record<string, unknown> }).args },
            transactionHash: log.transactionHash,
          });
        }

        // Sort by block number
        allEvents.sort((a, b) => Number(a.blockNumber - b.blockNumber));

        setEvents(allEvents);
      } catch (err) {
        if (!cancelled) {
          setError(
            err instanceof Error
              ? err.message
              : "Error al obtener eventos on-chain"
          );
        }
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    if (batchId > 0n) {
      fetchEvents();
    }

    return () => {
      cancelled = true;
    };
  }, [publicClient, batchId, contractAddress]);

  if (loading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">­ƒô£ Historial On-Chain</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="animate-pulse space-y-3">
            {[1, 2, 3].map((i) => (
              <div key={i} className="h-16 bg-muted rounded" />
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  if (error) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">­ƒô£ Historial On-Chain</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="text-center py-4">
            <p className="text-sm text-muted-foreground">{error}</p>
            <p className="text-xs text-muted-foreground mt-1">
              Conecta tu wallet o verifica que el nodo RPC est├® activo.
            </p>
          </div>
        </CardContent>
      </Card>
    );
  }

  if (events.length === 0) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">­ƒô£ Historial On-Chain</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-sm text-muted-foreground text-center py-4">
            No se encontraron eventos para este lote.
          </p>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-lg">­ƒô£ Historial On-Chain</CardTitle>
        <CardDescription>
          {events.length} evento{events.length !== 1 ? "s" : ""} registrado
          {events.length !== 1 ? "s" : ""} en la blockchain
        </CardDescription>
      </CardHeader>
      <CardContent>
        <div className="space-y-4">
          {events.map((event, i) => (
            <EventCard key={`${event.transactionHash}-${i}`} event={event} />
          ))}
        </div>
      </CardContent>
    </Card>
  );
}

function EventCard({ event }: { event: BatchEvent }) {
  const txShort = `${event.transactionHash.slice(0, 10)}...${event.transactionHash.slice(-8)}`;

  switch (event.type) {
    case "created": {
      const farmer = String(event.data.farmer ?? "");
      const ts = Number(event.data.timestamp ?? 0);
      return (
        <div className="flex items-start gap-3 p-3 rounded-lg bg-green-50 dark:bg-green-950/30 border border-green-200 dark:border-green-800">
          <span className="text-xl flex-shrink-0">­ƒî▒</span>
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 mb-1">
              <p className="text-sm font-medium">Lote Creado</p>
              <Badge variant="outline" className="text-xs">
                Block #{event.blockNumber.toString()}
              </Badge>
            </div>
            <p className="text-xs text-muted-foreground">
              Farmer: <span className="font-mono">{farmer.slice(0, 8)}...{farmer.slice(-6)}</span>
              {ts > 0 && (
                <> ÔÇó {new Date(ts * 1000).toLocaleDateString("es-EC")}</>
              )}
            </p>
            <p className="text-xs text-muted-foreground font-mono mt-0.5">
              tx: {txShort}
            </p>
          </div>
        </div>
      );
    }

    case "stateChanged": {
      const prevState = Number(event.data.previousState ?? 0) as BatchState;
      const newState = Number(event.data.newState ?? 0) as BatchState;
      const actor = String(event.data.actor ?? "");
      const notes = String(event.data.notes ?? "");
      const ts = Number(event.data.timestamp ?? 0);

      return (
        <div className="flex items-start gap-3 p-3 rounded-lg bg-muted/50 border">
          <span className="text-xl flex-shrink-0">
            {BATCH_STATE_ICONS[newState] ?? "­ƒöä"}
          </span>
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 mb-1 flex-wrap">
              <p className="text-sm font-medium">Cambio de Estado</p>
              <Badge variant="outline" className="text-xs">
                Block #{event.blockNumber.toString()}
              </Badge>
            </div>
            <div className="flex items-center gap-1 text-xs mb-1">
              <Badge
                variant="secondary"
                className={`${BATCH_STATE_COLORS[prevState]} text-white text-xs`}
              >
                {BATCH_STATE_LABELS[prevState]}
              </Badge>
              <span>ÔåÆ</span>
              <Badge
                variant="secondary"
                className={`${BATCH_STATE_COLORS[newState]} text-white text-xs`}
              >
                {BATCH_STATE_LABELS[newState]}
              </Badge>
            </div>
            {notes && (
              <p className="text-xs text-muted-foreground italic">&quot;{notes}&quot;</p>
            )}
            <p className="text-xs text-muted-foreground mt-0.5">
              Actor: <span className="font-mono">{actor.slice(0, 8)}...{actor.slice(-6)}</span>
              {ts > 0 && (
                <> ÔÇó {new Date(ts * 1000).toLocaleDateString("es-EC")}</>
              )}
            </p>
            <p className="text-xs text-muted-foreground font-mono mt-0.5">
              tx: {txShort}
            </p>
          </div>
        </div>
      );
    }

    case "metadataUpdated": {
      const ipfsHash = String(event.data.ipfsHash ?? "");
      return (
        <div className="flex items-start gap-3 p-3 rounded-lg bg-blue-50 dark:bg-blue-950/30 border border-blue-200 dark:border-blue-800">
          <span className="text-xl flex-shrink-0">­ƒôÄ</span>
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 mb-1">
              <p className="text-sm font-medium">Metadata Actualizada</p>
              <Badge variant="outline" className="text-xs">
                Block #{event.blockNumber.toString()}
              </Badge>
            </div>
            <p className="text-xs text-muted-foreground font-mono truncate">
              IPFS: {ipfsHash}
            </p>
            <p className="text-xs text-muted-foreground font-mono mt-0.5">
              tx: {txShort}
            </p>
          </div>
        </div>
      );
    }
  }
}

"use client";

import { useAccount, useConnect, useDisconnect } from "wagmi";
import { Button } from "@/components/ui/button";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet";
import { useState } from "react";

const CONNECTOR_ICONS: Record<string, string> = {
  MetaMask: "­ƒªè",
  "Coinbase Wallet": "­ƒöÁ",
  WalletConnect: "­ƒöù",
  Safe: "­ƒøí´©Å",
  Injected: "­ƒÆë",
};

/**
 * Bot├│n de conexi├│n multi-wallet
 * Soporta: MetaMask, WalletConnect, Coinbase Wallet, Safe
 */
export function ConnectButton() {
  const { address, isConnected, chain } = useAccount();
  const { connect, connectors, isPending } = useConnect();
  const { disconnect } = useDisconnect();
  const [open, setOpen] = useState(false);

  if (isConnected && address) {
    return (
      <div className="flex items-center gap-2">
