              <span className="text-2xl">
                {CONNECTOR_ICONS[connector.name] || "­ƒöÉ"}
              </span>
              <div>
                <p className="text-sm font-medium">{connector.name}</p>
                <p className="text-xs text-muted-foreground">
                  {connector.name === "MetaMask"
                    ? "Extensi├│n de navegador"
                    : connector.name === "WalletConnect"
                      ? "+400 wallets m├│viles"
                      : connector.name === "Coinbase Wallet"
                        ? "App & extensi├│n"
                        : connector.name === "Safe"
                          ? "Multisig (Gnosis)"
                          : "Wallet inyectada"}
                </p>
              </div>
            </button>
          ))}
        </div>
        <div className="mt-6 p-3 rounded-lg bg-muted text-xs text-muted-foreground">
          <p className="font-medium mb-1">Redes soportadas</p>
          <p>Polygon Amoy (Testnet) ÔÇó Anvil (Local)</p>
        </div>
      </SheetContent>
    </Sheet>
  );
}

